def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    prime_cache = {}
    def is_prime(num):
        if num < 2:
            return False
        if num in prime_cache:
            return prime_cache[num]
        for i in range(2, int(num ** 0.5) + 1):
            if num % i == 0:
                prime_cache[num] = False
                return False
        prime_cache[num] = True
        return True
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf if item > cap else 950
            continue
        ratio = item / cap
        score = 0
        if ratio < 0.1:
            for a in range(1, 10):
                exp_term = np.exp(-a * ratio * 7)
                sin_term = np.sin(cap / (a + 1) + a * np.pi / 3)
                prime_sum = 0
                for p in range(2, int(cap // 3) + 1):
                    if cap % p == 0 and is_prime(p):
                        prime_sum += p ** 0.6
                score += exp_term * sin_term * (15 / (a + 1)) + prime_sum * 0.8
            if cap % 7 == 0:
                score *= 1.15
        elif 0.1 <= ratio < 0.3:
            cos_val = np.cos(ratio * np.pi * 6) * 20
            harmonic_sum = 0
            for h in range(1, 8):
                harmonic_sum += ((-1) ** (h + 1)) * (1 / h) * ratio ** h
            score += cos_val + harmonic_sum * 12
            for divisor in [5, 8, 10]:
                if cap % divisor == 0:
                    score += divisor * 0.7
            if any(cap % d == 0 for d in [5,8,10]):
                score *= 1.1
        elif 0.3 <= ratio <= 0.6:
            sin_comp = np.sin(ratio * np.pi * 3) * 18
            comb_part = 0
            int_cap = int(min(10, cap))
            for r in range(1, int_cap):
                try:
                    comb_val = comb(int_cap, r)
                except OverflowError:
                    comb_val = 1e6
                comb_part += ((-1)**r) * (ratio ** r) / (r + 1) * np.log1p(comb_val)
            score += sin_comp + comb_part * 7
            for g in range(2, int_cap):
                if cap % g == 0 and g % 3 == 2:
                    score += np.sqrt(g) * 3
        elif 0.6 < ratio <= 0.8:
            logistic_part = 40 / (1 + np.exp(-30 * (ratio - 0.7)))
            cumulative_factorial = 0
            for f in range(1, 5):
                cumulative_factorial += ((-1) ** f) * (ratio ** f) / factorial(f)
            prime_factor_sum = 0
            for num in range(2, int(cap)):
                if is_prime(num) and cap % num == 0:
                    prime_factor_sum += np.log(num) * 2
            score += logistic_part + cumulative_factorial * 12 + prime_factor_sum
            if cap % 4 == 0:
                score *= 1.05
        elif 0.8 < ratio <= 1.0:
            sine_wave = np.sin(ratio * np.pi * 7) * 25
            mod_sum = 0
            for k in range(1, 12):
                mod_sum += ((k * ratio * 100) % 10) / 10
            score += sine_wave + mod_sum * 8
            prime_filtered = [p for p in range(2, 20) if is_prime(p) and p % 5 == 1]
            score += sum(prime_filtered) * 1.3 * (1 - ratio)
            if cap % 9 == 0:
                score *= 1.12
        elif 1.0 < ratio < 2.0:
            penalty = 0
            block_size = max(1, int(cap // 4))
            for i in range(1, block_size + 1):
                if cap % i == 0:
                    penalty += i ** 1.5
            fract = ratio - int(ratio)
            for j in range(1, 10):
                mod_val = (fract * j * 999) % 7
                penalty += (mod_val / 7) * 4
            score += penalty / (block_size + 3) + (ratio - 1) * (-65)
            if cap % 13 == 0:
                score *= 0.85
            if int(cap) % 17 == 0:
                score += 22
        elif 2.0 <= ratio < 3.5:
            complex_calc = 0
            upper_limit = int(min(20, cap))
            for k in range(1, upper_limit):
                if cap % k == 0:
                    if k % 3 == 0:
                        complex_calc += np.log1p(k) * 4
                    else:
                        complex_calc += np.sqrt(k) * 2.7
            fract_part = ratio - int(ratio)
            for m in range(1, 15):
                complex_calc += np.sin(fract_part * m * np.pi / 2) * 3
            score += complex_calc + (ratio - 2) * 75
            if ratio > 2.8:
                for n in range(1, int(cap // 4) + 1):
                    if n % 5 == 0:
                        score += np.cos(n * np.pi / 4) * 5
        else:
            nested_sum = 0
            limit = int(min(25, cap))
            for x in range(1, limit):
                if cap % x == 0:
                    nested_sum += np.sqrt(x) * np.cos(x) + np.log1p(x) * np.sin(x/2)
            fract_r = ratio - int(ratio)
            for y in range(1, 20):
                nested_sum += np.sin(fract_r * y * np.pi) * np.cos(fract_r * y)
            score += nested_sum + (ratio - 3.5) * 85
            if ratio > 5:
                for z in range(1, int(cap // 2) + 1):
                    if is_prime(z):
                        score += np.exp(-z / 10) * 6
        if int(cap) % 6 == 0 and ratio < 2:
            score *= 1.1
        if int(cap) % 15 == 0 and 0.4 < ratio < 1.5:
            score *= 0.88
        if ratio > 4 and int(cap) % 20 == 0:
            score += 35
        if int(cap) % 18 == 0:
            score *= 0.79
        if 1.5 < ratio < 2.5 and int(cap) % 7 == 0:
            score *= 1.12
        priorities[idx] = score
    finite_mask = np.isfinite(priorities)
    if np.any(finite_mask):
        min_priority = np.min(priorities[finite_mask])
    else:
        min_priority = 0
    priorities = np.where(finite_mask, priorities, min_priority + 350)
    return priorities
